package com.example.wanotification.audio

import android.content.Context
import android.speech.tts.TextToSpeech
import java.util.Locale

import com.example.wanotification.config.TTSSettingsManager

class TTSManager(
    private val context: Context
) : TextToSpeech.OnInitListener {

    private var tts: TextToSpeech =
        TextToSpeech(context, this)

    private var isReady = false

    override fun onInit(
        status: Int
    ) {

        if (status == TextToSpeech.SUCCESS) {

            tts.language = Locale("id", "ID")

            tts.setSpeechRate(1.0f)

            tts.setPitch(1.0f)

            isReady = true
        }
    }

    fun speak(
        text: String
    ) {

        if (!isReady) return

//        if (!TTSSettingsManager.isEnabled(context)) {
//            return
//        }

        tts.speak(
            text,
            TextToSpeech.QUEUE_FLUSH,
            null,
            null
        )
    }
}

package com.example.wanotification.audio

import android.content.Context
import android.speech.tts.TextToSpeech
import java.util.Locale

import com.example.wanotification.config.TTSSettingsManager
import com.example.wanotification.queue.SpeechQueueManager

class TTSManager(
    private val context: Context
) : TextToSpeech.OnInitListener {

    private var tts: TextToSpeech =
        TextToSpeech(context, this)

    private var isReady = false

    override fun onInit(
        status: Int
    ) {

        if (status == TextToSpeech.SUCCESS) {

            tts.language = Locale("id", "ID")

            tts.setSpeechRate(1.0f)

            tts.setPitch(1.0f)

            isReady = true
        }
    }

    fun speak(
        text: String
    ) {

        if (!isReady) return

        val utteranceId = "notif_${System.currentTimeMillis()}"

        tts.speak(
            text,
            TextToSpeech.QUEUE_ADD,
            null,
            utteranceId
        )
    }

    fun shutdown() {
        if (tts != null) {
            tts.stop()
            tts.shutdown()
        }
    }
}

